// This Pine Script® code is subject to the terms of the Mozilla Public License 2.0
// © Supply_Demand_BuySell_v6

//@version=6
indicator("Supply & Demand – Buy/Sell Signals + TP/SL", overlay=true, max_boxes_count=200, max_lines_count=400, max_labels_count=400)

// ═══════════════════════════════════════════════════════════════
//                        INPUTS
// ═══════════════════════════════════════════════════════════════
grp1 = "═══ Zone Detection ═══"
swingLen    = input.int(10,    "Swing Lookback",          minval=3,   maxval=50,  group=grp1)
zoneLookback= input.int(50,    "Zone History Bars",       minval=20,  maxval=200, group=grp1)
zoneStrength= input.int(2,     "Min Candles to Confirm",  minval=1,   maxval=5,   group=grp1)

grp2 = "═══ Display ═══"
showSupply  = input.bool(true, "Show Supply Zones",                               group=grp2)
showDemand  = input.bool(true, "Show Demand Zones",                               group=grp2)
showLabels  = input.bool(true, "Show Zone Labels",                                group=grp2)
showDash    = input.bool(true, "Show Dashboard",                                  group=grp2)
showTPSL    = input.bool(true, "Show TP / SL Lines",                              group=grp2)

grp3 = "═══ Risk Management ═══"
atrLen      = input.int(14,    "ATR Length",              minval=1,   maxval=50,  group=grp3)
rrMode      = input.string("Auto","RR Mode",              options=["Auto","1:1","1:1.5","1:2","1:3"], group=grp3)
slAtrMult   = input.float(0.8, "SL ATR Multiplier",       minval=0.2, maxval=3.0, group=grp3, step=0.1)

grp4 = "═══ Filters ═══"
useEma      = input.bool(true, "EMA Trend Filter",                                group=grp4)
emaLen      = input.int(200,   "EMA Length",              minval=20,  maxval=500, group=grp4)
useVolume   = input.bool(true, "Volume Spike Filter",                             group=grp4)
volMult     = input.float(1.5, "Volume Spike Multiplier", minval=1.0, maxval=5.0, group=grp4, step=0.1)

// ═══════════════════════════════════════════════════════════════
//              FUNCTION: RR RATIO
// ═══════════════════════════════════════════════════════════════
f_getRR(isStrong, isMedium) =>
    float r = 1.5
    if rrMode == "1:1"
        r := 1.0
    else if rrMode == "1:1.5"
        r := 1.5
    else if rrMode == "1:2"
        r := 2.0
    else if rrMode == "1:3"
        r := 3.0
    else
        r := isStrong ? 3.0 : isMedium ? 2.0 : 1.5
    r

// ═══════════════════════════════════════════════════════════════
//              CORE INDICATORS
// ═══════════════════════════════════════════════════════════════
atr    = ta.atr(atrLen)
ema200 = ta.ema(close, emaLen)
volAvg = ta.sma(volume, 20)

plot(useEma ? ema200 : na, "EMA", color=color.new(color.white, 45), linewidth=2)

// ─── Volume spike ─────────────────────────────────────────────
volSpike = useVolume ? volume > volAvg * volMult : true

// ─── Swing pivots ─────────────────────────────────────────────
swHigh = ta.pivothigh(high, swingLen, swingLen)
swLow  = ta.pivotlow(low,  swingLen, swingLen)

// ═══════════════════════════════════════════════════════════════
//   SUPPLY ZONE DETECTION
//   A supply zone forms at a swing high where:
//   - A strong bearish move followed
//   - Price has not yet returned to retest
//   Zone boundaries: top = swing high, bot = open of that candle
// ═══════════════════════════════════════════════════════════════
var float sz_top  = na
var float sz_bot  = na
var int   sz_bar  = na
var bool  sz_on   = false
var bool  sz_fresh= false
var int   sz_tests= 0
var box   sz_box  = na

// Detect new supply zone on swing high
if not na(swHigh)
    // Confirm bearish impulse after the swing high
    bearMove = close[swingLen] < open[swingLen]
    if bearMove
        sz_top   := high[swingLen]
        sz_bot   := math.min(open[swingLen], close[swingLen])
        sz_bar   := bar_index - swingLen
        sz_on    := true
        sz_fresh := true
        sz_tests := 0
        sz_box   := na

// Mitigation: zone broken when close goes above sz_top
if sz_on and not na(sz_top) and close > sz_top
    sz_on    := false
    sz_fresh := false
    if not na(sz_box)
        box.set_border_color(sz_box, color.new(color.red, 60))
        box.set_bgcolor(sz_box,      color.new(color.red, 92))

// Count retests
if sz_on and not na(sz_top) and high >= sz_bot and high <= sz_top
    sz_tests := sz_tests + 1

// Draw / extend supply box
if showSupply and sz_on and not na(sz_bar)
    if na(sz_box)
        sz_box := box.new(sz_bar, sz_top, bar_index, sz_bot,
                          bgcolor=color.new(color.red, 78),
                          border_color=color.new(color.red, 30),
                          border_width=1)
        if showLabels
            label.new(sz_bar, sz_top, "SUPPLY",
                      color=color.new(color.red, 20),
                      textcolor=color.white,
                      style=label.style_label_lower_right,
                      size=size.small)
    else
        box.set_right(sz_box, bar_index)

// Price inside supply zone?
inSupply = sz_on and not na(sz_top) and high >= sz_bot and low <= sz_top

// ═══════════════════════════════════════════════════════════════
//   DEMAND ZONE DETECTION
//   A demand zone forms at a swing low where:
//   - A strong bullish move followed
//   - Price has not yet returned to retest
//   Zone boundaries: top = open of that candle, bot = swing low
// ═══════════════════════════════════════════════════════════════
var float dz_top  = na
var float dz_bot  = na
var int   dz_bar  = na
var bool  dz_on   = false
var bool  dz_fresh= false
var int   dz_tests= 0
var box   dz_box  = na

// Detect new demand zone on swing low
if not na(swLow)
    bullMove = close[swingLen] > open[swingLen]
    if bullMove
        dz_top   := math.max(open[swingLen], close[swingLen])
        dz_bot   := low[swingLen]
        dz_bar   := bar_index - swingLen
        dz_on    := true
        dz_fresh := true
        dz_tests := 0
        dz_box   := na

// Mitigation: zone broken when close goes below dz_bot
if dz_on and not na(dz_bot) and close < dz_bot
    dz_on    := false
    dz_fresh := false
    if not na(dz_box)
        box.set_border_color(dz_box, color.new(color.green, 60))
        box.set_bgcolor(dz_box,      color.new(color.green, 92))

// Count retests
if dz_on and not na(dz_bot) and low <= dz_top and low >= dz_bot
    dz_tests := dz_tests + 1

// Draw / extend demand box
if showDemand and dz_on and not na(dz_bar)
    if na(dz_box)
        dz_box := box.new(dz_bar, dz_top, bar_index, dz_bot,
                          bgcolor=color.new(color.green, 78),
                          border_color=color.new(color.green, 30),
                          border_width=1)
        if showLabels
            label.new(dz_bar, dz_bot, "DEMAND",
                      color=color.new(color.green, 20),
                      textcolor=color.white,
                      style=label.style_label_upper_right,
                      size=size.small)
    else
        box.set_right(dz_box, bar_index)

// Price inside demand zone?
inDemand = dz_on and not na(dz_bot) and low <= dz_top and high >= dz_bot

// ═══════════════════════════════════════════════════════════════
//   ZONE STRENGTH
//   Strong  = fresh zone (never tested) + volume spike
//   Medium  = tested once + volume spike  OR  fresh + no vol
//   Basic   = tested 2+ times
// ═══════════════════════════════════════════════════════════════
szStrong = inSupply and sz_fresh and sz_tests == 0 and volSpike
szMedium = inSupply and (sz_tests <= 1) and volSpike and not szStrong
szBasic  = inSupply and not szStrong and not szMedium

dzStrong = inDemand and dz_fresh and dz_tests == 0 and volSpike
dzMedium = inDemand and (dz_tests <= 1) and volSpike and not dzStrong
dzBasic  = inDemand and not dzStrong and not dzMedium

// ═══════════════════════════════════════════════════════════════
//   REVERSAL CONFIRMATION CANDLES
//   Bearish reversal: bearish engulfing or shooting star at supply
//   Bullish reversal: bullish engulfing or hammer at demand
// ═══════════════════════════════════════════════════════════════

// Bearish engulfing
bearEngulf = close < open and close < open[1] and open > close[1] and
             (open - close) > (close[1] - open[1])

// Shooting star
shootingStar = (high - math.max(open, close)) > 2 * math.abs(close - open) and
               (math.min(open, close) - low) < (high - math.max(open, close)) * 0.3 and
               close < open

// Bullish engulfing
bullEngulf = close > open and close > open[1] and open < close[1] and
             (close - open) > (open[1] - close[1])

// Hammer
hammer = (math.min(open, close) - low) > 2 * math.abs(close - open) and
         (high - math.max(open, close)) < (math.min(open, close) - low) * 0.3 and
         close > open

bearConfirm = bearEngulf or shootingStar
bullConfirm = bullEngulf or hammer

// ═══════════════════════════════════════════════════════════════
//   EMA FILTER
// ═══════════════════════════════════════════════════════════════
emaOkSell = useEma ? close < ema200 : true
emaOkBuy  = useEma ? close > ema200 : true

// ═══════════════════════════════════════════════════════════════
//   SIGNALS
//   SELL: price enters supply zone + bearish reversal candle + below EMA
//   BUY:  price enters demand zone + bullish reversal candle + above EMA
// ═══════════════════════════════════════════════════════════════
sellSignal = inSupply and bearConfirm and emaOkSell
buySignal  = inDemand and bullConfirm and emaOkBuy

// ═══════════════════════════════════════════════════════════════
//   RR CALCULATION
// ═══════════════════════════════════════════════════════════════
sellRR = f_getRR(szStrong, szMedium)
buyRR  = f_getRR(dzStrong, dzMedium)

// ═══════════════════════════════════════════════════════════════
//   SIGNAL ARROWS
// ═══════════════════════════════════════════════════════════════
plotshape(buySignal,  "BUY",  shape.labelup,   location.belowbar,
          color=color.new(color.green, 0), textcolor=color.white, text="BUY",  size=size.normal)
plotshape(sellSignal, "SELL", shape.labeldown, location.abovebar,
          color=color.new(color.red, 0),   textcolor=color.white, text="SELL", size=size.normal)

bgcolor(buySignal  ? color.new(color.green, 88) : na, title="BUY  bg")
bgcolor(sellSignal ? color.new(color.red,   88) : na, title="SELL bg")

// ═══════════════════════════════════════════════════════════════
//   TP / SL LINES — dynamic, extend with chart
// ═══════════════════════════════════════════════════════════════
var line sl_line  = na
var line tp1_line = na
var line tp2_line = na
var label sl_lbl  = na
var label tp1_lbl = na
var label tp2_lbl = na

// ── BUY TP/SL ─────────────────────────────────────────────────
if showTPSL and buySignal
    if not na(sl_line)
        line.delete(sl_line)
    if not na(tp1_line)
        line.delete(tp1_line)
    if not na(tp2_line)
        line.delete(tp2_line)
    if not na(sl_lbl)
        label.delete(sl_lbl)
    if not na(tp1_lbl)
        label.delete(tp1_lbl)
    if not na(tp2_lbl)
        label.delete(tp2_lbl)

    slDist   = atr * slAtrMult
    slPrice  = close - slDist
    tp1Price = close + slDist * buyRR * 0.5
    tp2Price = close + slDist * buyRR

    sl_line  := line.new(bar_index, slPrice,  bar_index, slPrice,  extend=extend.right, color=color.new(color.red,    0), width=2, style=line.style_dashed)
    tp1_line := line.new(bar_index, tp1Price, bar_index, tp1Price, extend=extend.right, color=color.new(color.yellow, 0), width=1, style=line.style_dotted)
    tp2_line := line.new(bar_index, tp2Price, bar_index, tp2Price, extend=extend.right, color=color.new(color.lime,   0), width=2, style=line.style_dashed)
    sl_lbl   := label.new(bar_index, slPrice,  "  SL",                               color=color.new(color.red,    15), textcolor=color.white, style=label.style_label_right, size=size.small)
    tp1_lbl  := label.new(bar_index, tp1Price, "  TP1 (50%)",                        color=color.new(color.yellow, 15), textcolor=color.black, style=label.style_label_right, size=size.small)
    tp2_lbl  := label.new(bar_index, tp2Price, "  TP2  1:" + str.tostring(buyRR,  "#.#"), color=color.new(color.lime, 15), textcolor=color.black, style=label.style_label_right, size=size.small)

// ── SELL TP/SL ────────────────────────────────────────────────
if showTPSL and sellSignal
    if not na(sl_line)
        line.delete(sl_line)
    if not na(tp1_line)
        line.delete(tp1_line)
    if not na(tp2_line)
        line.delete(tp2_line)
    if not na(sl_lbl)
        label.delete(sl_lbl)
    if not na(tp1_lbl)
        label.delete(tp1_lbl)
    if not na(tp2_lbl)
        label.delete(tp2_lbl)

    slDist   = atr * slAtrMult
    slPrice  = close + slDist
    tp1Price = close - slDist * sellRR * 0.5
    tp2Price = close - slDist * sellRR

    sl_line  := line.new(bar_index, slPrice,  bar_index, slPrice,  extend=extend.right, color=color.new(color.red,    0), width=2, style=line.style_dashed)
    tp1_line := line.new(bar_index, tp1Price, bar_index, tp1Price, extend=extend.right, color=color.new(color.yellow, 0), width=1, style=line.style_dotted)
    tp2_line := line.new(bar_index, tp2Price, bar_index, tp2Price, extend=extend.right, color=color.new(color.lime,   0), width=2, style=line.style_dashed)
    sl_lbl   := label.new(bar_index, slPrice,  "  SL",                                color=color.new(color.red,    15), textcolor=color.white, style=label.style_label_right, size=size.small)
    tp1_lbl  := label.new(bar_index, tp1Price, "  TP1 (50%)",                         color=color.new(color.yellow, 15), textcolor=color.black, style=label.style_label_right, size=size.small)
    tp2_lbl  := label.new(bar_index, tp2Price, "  TP2  1:" + str.tostring(sellRR, "#.#"), color=color.new(color.lime, 15), textcolor=color.black, style=label.style_label_right, size=size.small)

// Keep labels pinned to current bar edge every tick
if showTPSL and not na(sl_lbl)
    label.set_x(sl_lbl,  bar_index)
    label.set_x(tp1_lbl, bar_index)
    label.set_x(tp2_lbl, bar_index)

// ═══════════════════════════════════════════════════════════════
//   ALERT CONDITIONS
// ═══════════════════════════════════════════════════════════════
alertcondition(buySignal,  "S&D BUY Signal",  "Supply & Demand BUY: Demand zone + Bullish candle + Above EMA")
alertcondition(sellSignal, "S&D SELL Signal", "Supply & Demand SELL: Supply zone + Bearish candle + Below EMA")

// ═══════════════════════════════════════════════════════════════
//   DASHBOARD
// ═══════════════════════════════════════════════════════════════
var table dash = table.new(position.top_right, 2, 13,
                           bgcolor=color.new(color.black, 55),
                           border_color=color.new(color.gray, 50), border_width=1,
                           frame_color=color.new(color.gray, 30),  frame_width=1)

if showDash and barstate.islast
    hdr = color.new(color.blue, 30)

    table.cell(dash, 0, 0,  "S&D INDICATOR",         text_color=color.white,  bgcolor=hdr, text_size=size.small)
    table.cell(dash, 1, 0,  timeframe.period + " TF", text_color=color.yellow, bgcolor=hdr, text_size=size.small)

    table.cell(dash, 0, 1,  "EMA 200",     text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 1,  close > ema200 ? "Above" : "Below",
               text_color=close > ema200 ? color.green : color.red, text_size=size.small)

    table.cell(dash, 0, 2,  "Volume",      text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 2,  volume > volAvg * volMult ? "Spike" : "Normal",
               text_color=volume > volAvg * volMult ? color.yellow : color.gray, text_size=size.small)

    table.cell(dash, 0, 3,  "Supply Zone", text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 3,  sz_on ? (inSupply ? "In Zone" : "Active") : "None",
               text_color=inSupply ? color.red : sz_on ? color.orange : color.gray, text_size=size.small)

    table.cell(dash, 0, 4,  "Supply Fresh",text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 4,  sz_on ? (sz_fresh ? "Fresh" : "Tested") : "--",
               text_color=sz_fresh ? color.red : color.gray, text_size=size.small)

    table.cell(dash, 0, 5,  "Supply Tests",text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 5,  sz_on ? str.tostring(sz_tests) : "--",
               text_color=sz_tests == 0 ? color.green : sz_tests == 1 ? color.yellow : color.red, text_size=size.small)

    table.cell(dash, 0, 6,  "Demand Zone", text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 6,  dz_on ? (inDemand ? "In Zone" : "Active") : "None",
               text_color=inDemand ? color.green : dz_on ? color.teal : color.gray, text_size=size.small)

    table.cell(dash, 0, 7,  "Demand Fresh",text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 7,  dz_on ? (dz_fresh ? "Fresh" : "Tested") : "--",
               text_color=dz_fresh ? color.green : color.gray, text_size=size.small)

    table.cell(dash, 0, 8,  "Demand Tests",text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 8,  dz_on ? str.tostring(dz_tests) : "--",
               text_color=dz_tests == 0 ? color.green : dz_tests == 1 ? color.yellow : color.red, text_size=size.small)

    table.cell(dash, 0, 9,  "Reversal",    text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 9,  bearConfirm ? "Bearish" : bullConfirm ? "Bullish" : "--",
               text_color=bearConfirm ? color.red : bullConfirm ? color.green : color.gray, text_size=size.small)

    qualStr = szStrong or dzStrong ? "Strong 1:3" : szMedium or dzMedium ? "Medium 1:2" : sellSignal or buySignal ? "Basic 1:1.5" : "--"
    qualCol = szStrong or dzStrong ? color.yellow : szMedium or dzMedium ? color.orange : color.gray
    table.cell(dash, 0, 10, "Zone Quality",text_color=color.gray, text_size=size.small)
    table.cell(dash, 1, 10, qualStr,       text_color=qualCol,   text_size=size.small)

    rrStr = buySignal ? "1:" + str.tostring(buyRR, "#.#") : sellSignal ? "1:" + str.tostring(sellRR, "#.#") : "--"
    table.cell(dash, 0, 11, "RR Ratio",    text_color=color.gray,  text_size=size.small)
    table.cell(dash, 1, 11, rrStr,         text_color=color.white, text_size=size.small)

    sigStr = buySignal ? "BUY" : sellSignal ? "SELL" : "Waiting"
    sigCol = buySignal ? color.lime : sellSignal ? color.red : color.gray
    table.cell(dash, 0, 12, "SIGNAL",      text_color=color.white, text_size=size.small, bgcolor=color.new(color.navy, 30))
    table.cell(dash, 1, 12, sigStr,        text_color=sigCol,      text_size=size.small, bgcolor=color.new(color.navy, 30))

