stBear = stDirection > 0  // price below supertrend = bearish

// — ATR for SL/TP —
atrVal = ta.atr(atrLen)

// — ADX Calculation —
[diPlus, diMinus, adxVal] = ta.dmi(adxLen, adxLen)
trendStrong = not useAdx or adxVal > adxThresh

// — Volume Filter —
volMA   = ta.sma(volume, volLen)
volOk   = not useVol or volume > volMA

// ═══════════════════════════════════════════════════════════════
//  ③ SIGNAL CONDITIONS
// ═══════════════════════════════════════════════════════════════

// Trend Bias
bullTrend = emaFast > emaMid and emaMid > emaSlow     // full bull stack
bearTrend = emaFast < emaMid and emaMid < emaSlow     // full bear stack

// RSI Conditions
rsiRecovery    = ta.crossover(rsi, rsiOS)             // RSI coming out of oversold
rsiRejection   = ta.crossunder(rsi, rsiOB)            // RSI coming out of overbought
rsiBullZone    = rsi > 45 and rsi < rsiOB             // RSI in healthy bull zone
rsiBearZone    = rsi < 55 and rsi > rsiOS             // RSI in healthy bear zone

// ─── BUY SIGNAL ─────────────────────────────────────────────
// All 5 conditions must align:
//  1. EMA stack bullish
//  2. RSI recovering from oversold OR in healthy bull zone + MACD crosses bull
//  3. MACD bullish cross
//  4. SuperTrend bullish (green)
//  5. Volume above average + ADX showing trend strength
buySignal = bullTrend
         and (rsiRecovery or (rsiBullZone and macdCrossBull))
         and macdBull
         and stBull
         and trendStrong
         and volOk
         and (tradeDir == "Both" or tradeDir == "Long Only")
         and inDateRange

// ─── SELL SIGNAL ─────────────────────────────────────────────
// All 5 conditions must align:
//  1. EMA stack bearish
//  2. RSI rejecting from overbought OR in healthy bear zone + MACD crosses bear
//  3. MACD bearish cross
//  4. SuperTrend bearish (red)
//  5. Volume above average + ADX showing trend strength
sellSignal = bearTrend
          and (rsiRejection or (rsiBearZone and macdCrossBear))
